mapper.sql:
WHERE s.merchant_id = #{merchantId}
  AND s.region = #{region}
  AND s.status = 1
  AND s.is_deleted = FALSE

    AND s.id IN
    #{shopId}


    AND s.category_id = #{query.categoryId}


    AND s.city_id = #{query.cityId}


    AND s.area_id = #{query.areaId}


    AND (
        LOWER(s.name) LIKE CONCAT('%', LOWER(#{query.keyword}), '%')
        OR LOWER(s.tags) LIKE CONCAT('%', LOWER(#{query.keyword}), '%')
        OR LOWER(s.address) LIKE CONCAT('%', LOWER(#{query.keyword}), '%')
    )


    AND s.price_per_capita >= #{query.minPrice}


    AND s.price_per_capita <= #{query.maxPrice}


    AND s.score >= #{query.minScore}


    AND s.has_deal = #{query.hasDeal}


    AND s.open_now = #{query.openNow}
